// Function node no n8n
return items.map(item => {
  const key = item.json?.body?.data?.key || {};
  const { remoteJid, remoteJidAlt } = key;

  let whatsappJid = null;

  if (remoteJidAlt && remoteJidAlt.includes('@s.whatsapp.net')) {
    whatsappJid = remoteJidAlt;
  } else if (remoteJid && remoteJid.includes('@s.whatsapp.net')) {
    whatsappJid = remoteJid;
  }

  // Se você quer que o OUTPUT tenha só o JID:
  return {
    json: {
      whatsappJid,
    },
  };
});

